// ─── PARSEAR MENSAJE BAILEYS ───
const raw = $input.first().json;
const messages = raw.messages || [];
if (!messages.length) return [{ json: { _skip: true } }];

const msg = messages[0];
const key = msg.key || {};
const message = msg.message || {};

let telefono = (key.remoteJid || '').replace('@s.whatsapp.net','').replace('@g.us','');
// No normalizar si es sesión webchat
if (!telefono.startsWith('webchat_')) {
  if (telefono.startsWith('+57'))  telefono = telefono.slice(3);
  if (telefono.startsWith('57') && telefono.length === 12) telefono = telefono.slice(2);
}

let texto = '';
let es_audio = false;
if (message.conversation)                                       texto = message.conversation.trim();
else if (message.extendedTextMessage?.text)                     texto = message.extendedTextMessage.text.trim();
else if (message.buttonsResponseMessage?.selectedButtonId)      texto = message.buttonsResponseMessage.selectedButtonId.trim();
else if (message.listResponseMessage?.singleSelectReply?.selectedRowId) texto = message.listResponseMessage.singleSelectReply.selectedRowId.trim();
else if (message.audioMessage || message.pttMessage)            { es_audio = true; texto = '[AUDIO]'; }
else if (message.imageMessage)                                  texto = '[IMAGEN]';
else if (message.documentMessage)                               texto = '[DOCUMENTO]';

const es_propio = key.fromMe === true;
const es_grupo  = (key.remoteJid || '').includes('@g.us');

if (!telefono || es_propio || es_grupo || !texto) {
  return [{ json: { _skip: true } }];
}

return [{ json: { telefono, texto_usuario: texto, es_audio, timestamp: new Date().toISOString() } }];

// ─── REDIS LOCK VIA HTTP (usando n8n fetch) ───
const item = $input.first().json;
const telefono = item.telefono;
const SB_URL = $vars.SUPABASE_URL;
const SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}`, 'Content-Type': 'application/json' };

// Usar Supabase como lock store (pragmatico, funciona en Code nodes)
try {
  // Verificar si hay lock activo (menos de 30 segundos)
  const r = await fetch(
    `${SB_URL}/rest/v1/vera_locks?telefono=eq.${encodeURIComponent(telefono)}&select=id,created_at`,
    { headers: { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` } }
  );
  const locks = await r.json();

  if (Array.isArray(locks) && locks.length > 0) {
    const lockAge = Date.now() - new Date(locks[0].created_at).getTime();
    if (lockAge < 30000) {
      return [{ json: { ...item, _locked: true } }];
    }
    // Lock expirado, eliminarlo
    await fetch(
      `${SB_URL}/rest/v1/vera_locks?telefono=eq.${encodeURIComponent(telefono)}`,
      { method: 'DELETE', headers: hdrs }
    );
  }

  // Adquirir lock
  await fetch(`${SB_URL}/rest/v1/vera_locks`, {
    method: 'POST',
    headers: { ...hdrs, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ telefono, created_at: new Date().toISOString() })
  });

  return [{ json: { ...item, _locked: false } }];
} catch(e) {
  // Si falla el lock, continuar sin lock
  return [{ json: { ...item, _locked: false } }];
}

// ─── ENVIAR AVISO LOCK + RELEASE ───
const item = $input.first().json;
const BAILEYS_URL = $vars.BAILEYS_URL || 'http://localhost:3006';
const SB_URL = $vars.SUPABASE_URL;
const SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const telWA = item.telefono.startsWith('57') ? item.telefono : `57${item.telefono}`;
const jid = `${telWA}@s.whatsapp.net`;

try {
  if (!item.telefono.startsWith('webchat_')) await fetch(`${BAILEYS_URL}/send`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ phone: jid, message: 'Estoy procesando tu mensaje anterior, dame un momento.' })
  });
} catch(e) { console.error('Error aviso lock:', e.message); }

return [{ json: { _skip: true, _locked_skip: true } }];

// ─── RATE LIMITER VIA SUPABASE ───
const item = $input.first().json;
const telefono = item.telefono;
const SB_URL = $vars.SUPABASE_URL;
const SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` };

const unMinutoAtras = new Date(Date.now() - 60000).toISOString();
const telBD = telefono.startsWith('webchat_') ? `+${telefono}` : (telefono.startsWith('57') ? `+${telefono}` : `+57${telefono}`);

try {
  const r = await fetch(`${SB_URL}/rest/v1/conversaciones_whatsapp?telefono=eq.${encodeURIComponent(telBD)}&rol=eq.user&created_at=gte.${unMinutoAtras}&select=id`, { headers: hdrs });
  const msgs = await r.json();
  if (Array.isArray(msgs) && msgs.length > 10) {
    return [{ json: { ...item, _rate_limited: true } }];
  }
} catch(e) { /* Si falla rate limit check, continuar */ }

return [{ json: { ...item, _rate_limited: false } }];

