// ─── CARGAR CONTEXTO COMPLETO + HISTORIAL DESDE SUPABASE ───
const item     = $input.first().json;
const telefono = item.telefono;
const SB_URL   = $vars.SUPABASE_URL;
const SB_KEY   = $vars.SUPABASE_SERVICE_KEY;
const telBD    = telefono.startsWith('webchat_') ? `+${telefono}` : (telefono.startsWith('57') ? `+${telefono}` : `+57${telefono}`);

const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` };

const CTX_VACIO = {
  numero_en_base:false, propietario_bloqueado:false, habeas_data_aceptado:false,
  primera_vez:true, nombre_usuario:null, tipo_usuario:null, es_delegado:false,
  nombre_unidad:null, coeficiente:null, nombre_edificio:null, correo_registrado:null,
  datos_faltantes:[], acreditacion_estado:'sin_acreditar', delegacion_pendiente:false,
  qr_generado:false, qr_escaneado:false, fecha_asamblea:null, hora_asamblea:null,
  nombre_asamblea:null, estado_asamblea:null, url_documentacion:null,
  asamblea_id:null, participante_id:null,
  votacion_activa:false, pregunta_actual_texto:null, pregunta_actual_id:null,
  opciones_voto:null, tipo_calculo:null, tiempo_restante_min:null, ya_voto_pregunta_actual:false
};

try {
  // 1. Contexto del usuario
  const r1 = await fetch(`${SB_URL}/rest/v1/contexto_usuario_whatsapp?telefono=eq.${encodeURIComponent(telBD)}&limit=1`, { headers: hdrs });
  const [ctx] = await r1.json();

  // 2. Historial (ultimos 8 mensajes, truncar a 2000 chars)
  const r2 = await fetch(`${SB_URL}/rest/v1/conversaciones_whatsapp?telefono=eq.${encodeURIComponent(telBD)}&order=created_at.desc&limit=8`, { headers: hdrs });
  const hist = await r2.json();
  const memoria_raw = Array.isArray(hist)
    ? hist.reverse().map(m => `${m.rol==='user'?'Usuario':'VERA'}: ${m.contenido}`).join('\n')
    : 'Sin historial previo.';
  const memoria = memoria_raw.length > 2000 ? memoria_raw.slice(-2000) : memoria_raw;

  if (!ctx) {
    return [{ json: { telefono, texto_usuario: item.texto_usuario, es_audio: item.es_audio, memoria_conversacion: memoria, contexto: { ...CTX_VACIO } } }];
  }

  // 3. Votacion activa
  let votacion_activa=false, pregunta_actual_texto=null, pregunta_actual_id=null;
  let opciones_voto=null, tipo_calculo=null, tiempo_restante_min=null, ya_voto_pregunta_actual=false;

  if (ctx.estado_asamblea === 'EN_CURSO' && ctx.qr_escaneado) {
    const r3 = await fetch(`${SB_URL}/rest/v1/preguntas?asamblea_id=eq.${ctx.asamblea_id}&estado=eq.Activa&limit=1`, { headers: hdrs });
    const [preg] = await r3.json();
    if (preg) {
      votacion_activa=true; pregunta_actual_texto=preg.texto; pregunta_actual_id=preg.id;
      opciones_voto=(preg.opciones_json||[]).join(' / '); tipo_calculo=preg.tipo_calculo||'coeficiente';
      if (preg.fecha_cierre_ronda) {
        tiempo_restante_min = Math.max(0, Math.round((new Date(preg.fecha_cierre_ronda)-new Date())/60000));
      }
      const r4 = await fetch(`${SB_URL}/rest/v1/votos?participante_id=eq.${ctx.participante_id}&pregunta_id=eq.${preg.id}&limit=1`, { headers: hdrs });
      const [vEx] = await r4.json();
      ya_voto_pregunta_actual = !!vEx;
    }
  }

  return [{ json: {
    telefono, texto_usuario: item.texto_usuario, es_audio: item.es_audio,
    memoria_conversacion: memoria,
    contexto: {
      numero_en_base: true,
      propietario_bloqueado:   ctx.propietario_bloqueado  || false,
      habeas_data_aceptado:    ctx.habeas_data_aceptado   || false,
      primera_vez:             ctx.primera_vez            || false,
      nombre_usuario:          ctx.nombre_usuario,
      tipo_usuario:            ctx.tipo_usuario,
      es_delegado:             ctx.tipo_usuario === 'delegado',
      nombre_unidad:           ctx.nombre_unidad,
      coeficiente:             ctx.coeficiente,
      nombre_edificio:         ctx.nombre_edificio,
      correo_registrado:       ctx.email_acreditacion,
      datos_faltantes:         ctx.datos_faltantes || [],
      acreditacion_estado:     ctx.acreditacion_estado || 'sin_acreditar',
      delegacion_pendiente:    ctx.delegacion_pendiente   || false,
      qr_generado:             ctx.qr_generado            || false,
      qr_escaneado:            ctx.qr_escaneado           || false,
      fecha_asamblea:          ctx.fecha_asamblea,
      hora_asamblea:           ctx.hora_asamblea,
      nombre_asamblea:         ctx.nombre_asamblea,
      estado_asamblea:         ctx.estado_asamblea,
      url_documentacion:       ctx.url_documentacion,
      asamblea_id:             ctx.asamblea_id,
      participante_id:         ctx.participante_id,
      votacion_activa, pregunta_actual_texto, pregunta_actual_id,
      opciones_voto, tipo_calculo, tiempo_restante_min, ya_voto_pregunta_actual
    }
  }}];
} catch(e) {
  return [{ json: { telefono, texto_usuario: item.texto_usuario, es_audio: item.es_audio, memoria_conversacion:'Sin historial previo.', _ctx_error: e.message, contexto: { ...CTX_VACIO } } }];
}

