const ctx = $('🧠 Cargar Contexto').first().json;
const SB_URL = $vars.SUPABASE_URL, SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}`, 'Content-Type': 'application/json' };

const codigo = ($input.item.json.codigo_acceso || '').trim().toUpperCase();
const telefono = ctx.telefono;
const telBD = telefono.startsWith('webchat_') ? `+${telefono}` : (telefono.startsWith('57') ? `+${telefono}` : `+57${telefono}`);

if (!/^[A-Z0-9]{5}$/.test(codigo)) {
  return 'Error: El codigo de acceso debe tener exactamente 5 caracteres alfanumericos.';
}

const r1 = await fetch(`${SB_URL}/rest/v1/estado_acreditacion_completo?codigo_acceso=eq.${codigo}&limit=1`, { headers: { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` } });
const [p] = await r1.json();

if (!p) return 'Error: Codigo no encontrado. Pide al usuario que verifique el correo de convocatoria.';
if (['CERRADA','CANCELADA'].includes(p.estado_asamblea)) return 'Error: Esta asamblea ya finalizo. No es posible acreditarse.';

await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${p.participante_id}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ telefono_whatsapp: telBD, primera_vez: false }) });

return `Codigo valido. Numero vinculado a la unidad ${p.nombre_unidad} del edificio ${p.nombre_edificio || ''}.`;

const ctx = $('🧠 Cargar Contexto').first().json;
const SB_URL = $vars.SUPABASE_URL, SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}`, 'Content-Type': 'application/json' };
