return 'Habeas data aceptado exitosamente. Continuar con el proceso de acreditacion.';

// ─── TOOL: ACTUALIZAR DATOS PARTICIPANTE ───
const ctx = $('🧠 Cargar Contexto').first().json;
const SB_URL = $vars.SUPABASE_URL, SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}`, 'Content-Type': 'application/json' };
const N8N_BASE = $vars.N8N_WEBHOOK_BASE || 'https://tu-dominio.com/webhook';
const RESEND_KEY = $vars.RESEND_API_KEY;

const campo = ($input.item.json.campo || '').trim().toLowerCase();
const valor = ($input.item.json.valor || '').trim();
const pid = ctx.contexto?.participante_id;

if (!campo || !valor) return 'Error: No se recibio el dato a actualizar.';

if (campo === 'email') {
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(valor)) return 'Error: El correo no es valido.';
  const expires = new Date(Date.now() + 24*3600000).toISOString();
  await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ email_acreditacion: valor, email_confirmado: false, email_token_expires_at: expires }) });

  const r1 = await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}&select=email_token,unidades(propietario_nombre),asambleas(nombre_evento)`, { headers: { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` } });
  const [p] = await r1.json();
  const link = `${N8N_BASE}/acreditacion/confirmar-email/${p?.email_token}`;
  const nombre = p?.unidades?.propietario_nombre || 'Propietario';
  const asamblea = p?.asambleas?.nombre_evento || 'la asamblea';

  try {
    await fetch('https://api.resend.com/emails', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${RESEND_KEY}` },
      body: JSON.stringify({
        from: 'Asamblea360 <noreply@tu-dominio.com>',
        to: [valor],
        subject: `Confirma tu correo — ${asamblea}`,
        html: `<p>Hola <strong>${nombre}</strong>,</p><p>Confirma tu correo para <strong>${asamblea}</strong>:</p><p><a href='${link}' style='background:#1B3A6B;color:white;padding:12px 24px;text-decoration:none;border-radius:6px;display:inline-block'>Confirmar correo</a></p><p style='color:#999;font-size:12px'>Valido 24h. Si no solicitaste esto, ignora este mensaje.</p>`
      })
    });
  } catch(e) { console.error('Resend error:', e.message); }

  return `Email registrado. Enlace de confirmacion enviado a ${valor}. El usuario debe revisar su correo y hacer clic en el enlace.`;
}

if (campo === 'cedula') {
  if (!/^\d{6,12}$/.test(valor)) return 'Error: La cedula debe tener entre 6 y 12 digitos numericos.';
  await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ documento_numero: valor }) });
  return 'Cedula actualizada exitosamente.';
}

if (campo === 'tipo_documento') {
  const tipos_validos = ['CC', 'CE', 'NIT', 'PP', 'TI'];
  const v = valor.toUpperCase();
  if (!tipos_validos.includes(v)) return `Error: Tipo de documento no valido. Opciones: ${tipos_validos.join(', ')}.`;
  await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ tipo_documento: v }) });
  return 'Tipo de documento actualizado exitosamente.';
}

if (campo === 'nombre') {
  if (valor.length < 3) return 'Error: El nombre debe tener al menos 3 caracteres.';
  await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ nombre_participante: valor }) });
  return 'Nombre actualizado exitosamente.';
}

return `Error: No se puede actualizar el campo "${campo}". Campos validos: email, nombre, cedula, tipo_documento.`;

const ctx = $('🧠 Cargar Contexto').first().json;
const SB_URL = $vars.SUPABASE_URL, SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const BAILEYS_URL = $vars.BAILEYS_URL || 'http://localhost:3006';
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}`, 'Content-Type': 'application/json' };
const pid = ctx.contexto?.participante_id;
const telefono = ctx.telefono;
const telWA = telefono.startsWith('57') ? telefono : `57${telefono}`;
const jid = `${telWA}@s.whatsapp.net`;

if (!pid) return 'Error: No se encontro perfil. Escalar a soporte.';

const otp = String(Math.floor(100000 + Math.random() * 900000));
const expires = new Date(Date.now() + 10 * 60000).toISOString();

await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, {
  method: 'PATCH', headers: hdrs,
  body: JSON.stringify({ celular_otp: otp, celular_otp_expires_at: expires, celular_intentos_otp: 0 })
});

try {
  await fetch(`${BAILEYS_URL}/send`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ phone: jid, message: `Tu codigo de verificacion: ${otp}\n\nValido por 10 minutos. No lo compartas con nadie.` })
  });
} catch(e) { return 'Error: No se pudo enviar el OTP. Intentar de nuevo.'; }

return 'Codigo de verificacion enviado al WhatsApp del usuario. Pedirle que ingrese los 6 digitos.';

const ctx = $('🧠 Cargar Contexto').first().json;
const SB_URL = $vars.SUPABASE_URL, SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const hdrs = { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}`, 'Content-Type': 'application/json' };
const pid = ctx.contexto?.participante_id;
const otp = String($input.item.json.otp || '').trim();

if (!otp || otp.length !== 6 || isNaN(Number(otp))) return 'Error: El codigo debe tener 6 digitos.';

const r1 = await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}&select=celular_otp,celular_otp_expires_at,celular_intentos_otp`, { headers: { 'apikey': SB_KEY, 'Authorization': `Bearer ${SB_KEY}` } });
const [p] = await r1.json();

if (!p) return 'Error: No se encontro perfil. Escalar a soporte.';
if ((p.celular_intentos_otp||0) >= 5) return 'Error: Demasiados intentos. El usuario debe reiniciar el proceso.';
if (p.celular_otp_expires_at && new Date(p.celular_otp_expires_at) < new Date()) return 'Error: El codigo expiro. Enviar uno nuevo.';

await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ celular_intentos_otp: (p.celular_intentos_otp||0)+1 }) });

if (p.celular_otp !== otp) {
  const rest = 4 - (p.celular_intentos_otp||0);
  return `Error: Codigo incorrecto. Quedan ${rest} intento(s).`;
}

await fetch(`${SB_URL}/rest/v1/participantes_asamblea?id=eq.${pid}`, { method: 'PATCH', headers: hdrs, body: JSON.stringify({ celular_confirmado: true, celular_otp: null, celular_intentos_otp: 0 }) });
return 'Celular verificado exitosamente.';

const ctx = $('🧠 Cargar Contexto').first().json;
const SB_URL = $vars.SUPABASE_URL, SB_KEY = $vars.SUPABASE_SERVICE_KEY;
const BAILEYS_URL = $vars.BAILEYS_URL || 'http://localhost:3006';
const RESEND_KEY = $vars.RESEND_API_KEY;
const APP_QR = $vars.APP_QR_BASE || 'https://tu-dominio.com/qr';
